var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"인사가 늦었군요. 아카데미 총학생회장, 옌 싱 란체스터라고 합니다.","JPN":"挨拶が遅れました。アカデミー生徒会長、イェン・シング・ランチェスターと申します。","ENG":"Please excuse me for the late introduction. I'm Yen Xing Lanchester, Student President of the Academy.","TWN":"抱歉沒能及時打招呼，我是學院學生會的會長嫣杏·蘭賈斯特。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"도움에 감사드립니다. 혹시 아카데미 본대에서 온 태스크포스신가요?","JPN":"ご支援いただきありがとうございます。もしかしてアカデミー本隊から来たタスクフォースカンパニーですか？","ENG":"Thank you for coming to our aid. Are you the TASKFORCE from the Academy's main camp?","TWN":"感謝你們的幫助。你們是學院營地派來的特遣勢力嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 잘못 보셨네요. 그런 거창한 신분은 아니고, 그냥 작은 태스크포스 컴퍼니 소속입니다.","JPN":"ハハ、違います。そんな偉そうな感じではなく、ただの小さいタスクフォースカンパニーに所属した者です。","ENG":"Hah hah, you must be mistaken. I'm just a nobody working for a tiny TASKFORCE company.","TWN":"哈哈，你猜錯了。我們沒有那麼大的來頭，只是所屬一個小特遣勢力公司的隊伍而已。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"탐사 중에 이쪽 좌표에서 문제가 발생한 걸 확인한 저희 부사장님이 긴급 출동을 명령하셨거든요.","JPN":"探査中にこの座標で問題が発生したことに気付いた副社長が、緊急出動を命令されたんです。","ENG":"Our Vice President noticed something went awry at these coordinates during our exploration and sent us here.","TWN":"在探測途中發現這邊的座標發生了問題，所以我們的副總命令緊急出動。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"공짜로 일하는 걸 세상에서 제일 싫어하는 분인데 무슨 바람이 불었는지 모르겠다니까요.","JPN":"無報酬で働くことを世界で一番嫌がるお方なのに、どういう風の吹き回しかわからないですけどね。","ENG":"She hates pro bono work with a passion, so I have no idea what got into her.","TWN":"她是世界上最討厭免費做事的人，但今天不知道為什麼會做出這樣的決定。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"통신 두절로 본대도 이곳 상황을 모르는데...... 어떻게 알고 오신 거죠?","JPN":"通信断絶で本隊もこちらの状況を知らないはずなのに……どうやって来たんですか？","ENG":"But even our main camp is unaware of the situation here, due to communication problems. How did you know about us?","TWN":"因為通信中斷，我們的營地也不知道這邊的情況……你們是怎麼知道的？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"글쎄요. 저 같은 말단은 시키면 시키는 대로 하는 게 일이라서요.","JPN":"さあ。僕みたいな末端社員は言われたことをするのが仕事なので。","ENG":"I don't know. Grunts like me have no choice but to do as we're told.","TWN":"這個嘛，像我這樣的低級職員只是按照指示辦事。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"자세한 사정에 대해서는 잘 모르겠네요.","JPN":"詳しい事情はわかりませんね。","ENG":"I don't know the details.","TWN":"所以詳細的情況我也不太瞭解。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그나저나 며칠 전에 혹시 유미나 양이라는 분이 편입하지 않았나요?","JPN":"ところで、もしかして数日前にヤナギ・ミナという子が編入していませんか？","ENG":"By the way, didn't you get a new transfer student named Yoo Mina a few days ago?","TWN":"不過，幾天前是不是有個叫劉米娜的學生入學？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"유미나 학생과 아는 사이셨나요?","JPN":"ヤナギ・ミナさんとはお知り合いですか？","ENG":"You know her?","TWN":"你認識劉米娜同學嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네, 저희 소대원이거든요.","JPN":"はい、同じ小隊員です。","ENG":"Yes. She's a member of my squad, actually.","TWN":"嗯，她是我們小隊的隊員。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"싸우면서 여기저기 둘러 봤는데 어째 보이질 않네요.","JPN":"戦闘しながらちょっと探してみたんですが、いなさそうで。","ENG":"I looked around during the battle, but I couldn't find her anywhere.","TWN":"剛才在戰鬥的時候，我四處看了下，沒看到她。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"유미나 양은 무단 이탈한 학생들을 구출하기 위해 방어선 밖으로 나갔습니다.","JPN":"ヤナギ・ミナさんは無断で離脱した生徒を救出するために、防御ラインの外に出ています。","ENG":"Mina went beyond the defensive perimeter to save some students who went AWOL.","TWN":"劉米娜同學去防禦線外圍解救無故脫離防線的學生了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그러고 보니 올 시간이 지났는데...... 아직 모습을 보이지 않는군요.","JPN":"でもそろそろ戻ってくる時間ですが……まだ見えませんね。","ENG":"She should be back by now... But she hasn't shown up yet.","TWN":"不過也該回來了……怎麼還沒見到她們呢。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"흠......","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"부사장님이 왜 저희를 급하게 보내셨는지 조금은 알 것 같네요.","JPN":"副社長がなぜ僕たちを急いで派遣したのかちょっとわかった気がします。","ENG":"I'm beginning to understand why the Vice President dispatched us so urgently.","TWN":"我大概能猜到為什麼副總讓我們緊急出動了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양 실력이라면 그리 위험한 일은 없을 것 같지만......","JPN":"ミナさんの実力であれば、さほど危険なことはないと思いますが……","ENG":"Although I'm sure Mina can handle herself here...","TWN":"雖然以米娜的實力應該不會有太大危險……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이면세계란 원래 아무것도 확신할 수 없는 곳이니까요.","JPN":"裏世界は何事も問題ないと確信できない場所ですから。","ENG":"Nobody can be certain about anything in the Counterside.","TWN":"但畢竟是在異界，誰都無法保證。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무래도 구출대를 보내는 편이 좋을 것 같네요.","JPN":"どうやら救出隊を送ったほうがよさそうです。","ENG":"I think it would be prudent to send out a rescue team.","TWN":"看來最好還是派出救援部隊吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"제가 안내하죠.","JPN":"私がご案内します。","ENG":"I'll lead the way.","TWN":"我引路。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"도와 주신 덕분에 이 곳의 적들은 대부분 정리된 것 같으니까요.","JPN":"助けていただいたおかげで、こちらの敵はほとんど片付いたようですから。","ENG":"Thanks to your help, I think this area is mostly secure now.","TWN":"多虧你們的幫助，這邊的敵人差不多已經清理完了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스, 제가 미나 소대원들을 찾으러 가는 동안 학생들을 부탁할게요.","JPN":"イーディス、私がミナ小隊員たちを探しにいく間、生徒たちをお願いします。","ENG":"Edith, please look after the students while I go find the members of the Mina Squad.","TWN":"伊蒂絲，我去找米娜小隊成員期間，學生們就拜託你了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 소대?","JPN":"ミナ小隊？","ENG":"Mina Squad?","TWN":"米娜小隊？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"방금 미나 소대라고 했어, 선배?","JPN":"今ミナ小隊って言ったの、先輩？","ENG":"Did you just say Mina Squad, Shiyoon?","TWN":"剛才是說米娜小隊嗎，前輩？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"내가 제대로 들은 거 맞아? 통신이 이상한 거 아니지?","JPN":"聞き間違いじゃないよね？　通信障害じゃないよね？","ENG":"Did I hear that right? It's not the comms acting up again, is it?","TWN":"我沒聽錯吧？不會是通信異常聽錯了吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"뭐야! 안 그런 척 하더니 꽤 야망이 큰 녀석이었잖아?","JPN":"なんだ！　肩書きには散々興味ないふりしたくせに、実はそんな野望を抱いていたんだな！","ENG":"Jeez! Who knew she was so ambitious? She never let it on!","TWN":"什麼嘛？平常完全沒看出來，那個傢伙原來野心這麼大？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"글쎄. 미나가 요새 강해지긴 했어도 힐데 소대장을 자리에서 몰아내긴 어려울 것 같은데.","JPN":"さあね。最近強くなったのは確かだけど、ヒルデ小隊長を今の地位から追い出すのは難しいじゃない。","ENG":"I don't know. Mina may have become stronger, but she'll be hard pressed if she wants to usurp Commander Hilde's mantle.","TWN":"就是說啊。雖然米娜最近變強了很多，但還不能頂替希爾德小隊長吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"풉, 푸하하하하하!!","JPN":"ぷっ！　あははははは！","ENG":"Pfft... Hah hah hah hah!","TWN":"噗，噗哈哈哈！！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"노, 놀리면 안 돼. 얘들아!","JPN":"か、からかうのはダメだよ、みんな！","ENG":"D-don't make fun of it, guys!","TWN":"你們不能取笑她！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"귀여운 소대명이긴 하지만...... 부, 분명 뭔가 이유가 있을 거야!","JPN":"可愛い小隊名だけど……き、きっと何か理由があるはずだよ！","ENG":"I mean, it's a cute name for a squad... B-but I'm sure there's a good reason!","TWN":"雖然是挺可愛的小隊名字……但，應該是有她的理由！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......이것 참, 들어선 안 될 걸 들은 것 같군요.","JPN":"……やれやれ。聞いてはいけないことを聞いちゃいましたね。","ENG":"Oh my. I don't think I was meant to hear that.","TWN":"……我好像聽到了不該聽到事情。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양도 당분간 직장생활이 고달프겠어요.","JPN":"ミナさんもしばらく、社内でネタにされそうですね。","ENG":"It sounds like Mina's going to have a tough time at the office for a while now.","TWN":"看來接下來有一陣子米娜的職場生活會有些頭疼。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};